class Solution {
public:
    bool isRationalEqual(string s, string t) {
        return stringToDouble(s) == stringToDouble(t);
    }

    double stringToDouble(string s) {
        int integerPart = 0;
        int nonRepeatingPart = 0;
        int repeatingPart = 0;
        int nonRepeatingLength = 0;
        int repeatingLength = 0;
        bool hasDecimal = false;
        bool hasRepeating = false;
        int i = 0;

        // Parse integer part
        while (i < s.size() && s[i] != '.') {
            integerPart = integerPart * 10 + (s[i++] - '0');
        }

        // Parse non-repeating and repeating parts
        if (i < s.size()) {
            hasDecimal = true;
            i++;
            while (i < s.size() && s[i] != '(') {
                nonRepeatingPart = nonRepeatingPart * 10 + (s[i++] - '0');
                nonRepeatingLength++;
            }
            if (i < s.size()) {
                hasRepeating = true;
                int start = i + 1;
                while (i < s.size()) {
                    repeatingPart = repeatingPart * 10 + (s[i++] - '0');
                    repeatingLength++;
                }
            }
        }

        // Calculate double value
        double value = integerPart;
        if (hasDecimal) {
            value += static_cast<double>(nonRepeatingPart) / pow(10, nonRepeatingLength);
            if (hasRepeating) {
                value += static_cast<double>(repeatingPart) / (pow(10, nonRepeatingLength) * (pow(10, repeatingLength) - 1));
            }
        }
        return value;
    }
};
